/**
 * AnalyticsPage.js — Détection IA Isolation Forest (v2 — simple & stable)
 * Affiche KPIs, carte Leaflet auto-refresh (10s), tableau anomalies.
 */
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MapContainer, TileLayer, CircleMarker, Popup, useMap } from 'react-leaflet';
import {
  BrainCircuit, Activity, AlertTriangle, CheckCircle2,
  RadioTower, Search, RefreshCw
} from 'lucide-react';
import axios from 'axios';
import L from 'leaflet';
import Sidebar from '../components/Sidebar';
import { API_BASE_URL } from '../apiConfig';
import { useAuth } from '../auth/AuthContext';
import '../styles/AnalyticsStyles.css';

// Fix Leaflet default icon
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
  iconUrl:       'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
  shadowUrl:     'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
});

const POLL_MS = 10000; // 10 secondes

// Couleurs selon statut
function couleurStatut(statut) {
  if (statut === 'critique') return '#dc2626';
  if (statut === 'alerte')   return '#d97706';
  return '#059669';
}

// Composant interne pour fitter la carte sur les marqueurs
function FitBounds({ antennes }) {
  const map = useMap();
  useEffect(() => {
    if (!antennes || antennes.length === 0) return;
    const pts = antennes
      .filter(a => a.latitude && a.longitude)
      .map(a => [parseFloat(a.latitude), parseFloat(a.longitude)]);
    if (pts.length > 0) {
      try { map.fitBounds(pts, { padding: [30, 30] }); } catch (_) {}
    }
  }, [antennes, map]);
  return null;
}

export default function AnalyticsPage() {
  const { token } = useAuth();
  const [antennes, setAntennes] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [search, setSearch]     = useState('');
  const [analyzing, setAnalyzing] = useState(false);
  const [lastUpdate, setLastUpdate] = useState(null);
  const isMounted = useRef(true);

  // ── Fetch données ──────────────────────────────────────────
  const fetchData = useCallback(async (isFirst = false) => {
    if (!token) return;
    try {
      const headers = { Authorization: `Bearer ${token}` };
      const res = await axios.get(`${API_BASE_URL}/antennes`, { headers });
      const data = res.data || [];
      console.log(`[IA] Antennes reçues : ${data.length}`, data.slice(0, 3));
      if (isMounted.current) {
        setAntennes(data);
        setLastUpdate(new Date());
        if (isFirst) setLoading(false);
      }
    } catch (err) {
      console.error('[IA] Erreur fetch antennes :', err);
      if (isFirst && isMounted.current) setLoading(false);
    }
  }, [token]);

  useEffect(() => {
    isMounted.current = true;
    fetchData(true);
    const id = setInterval(() => fetchData(false), POLL_MS);
    return () => {
      isMounted.current = false;
      clearInterval(id);
    };
  }, [fetchData]);

  // ── Forcer analyse IA ──────────────────────────────────────
  const forceIA = async () => {
    setAnalyzing(true);
    try {
      await axios.get(`${API_BASE_URL}/internal/predict`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      await fetchData(false);
    } catch (_) {}
    setTimeout(() => setAnalyzing(false), 1500);
  };

  // ── KPIs ───────────────────────────────────────────────────
  const nb = {
    total:    antennes.length,
    normal:   antennes.filter(a => a.statut === 'normal').length,
    alerte:   antennes.filter(a => a.statut === 'alerte').length,
    critique: antennes.filter(a => a.statut === 'critique').length,
  };
  const avgRisk = antennes.length > 0
    ? (antennes.reduce((s, a) => s + (Number(a.risk_score) || 0), 0) / antennes.length).toFixed(1)
    : '0.0';

  // ── Tableau filtré + trié par score décroissant ────────────
  const tableau = antennes
    .filter(a => {
      if (!search) return true;
      return a.nom?.toLowerCase().includes(search.toLowerCase()) ||
             a.zone?.toLowerCase().includes(search.toLowerCase());
    })
    .sort((a, b) => (Number(b.risk_score) || 0) - (Number(a.risk_score) || 0));

  // ── Marqueurs carte — tous les statuts ────────────────────
  const marqueurs = antennes.filter(a =>
    a.latitude && a.longitude &&
    !isNaN(parseFloat(a.latitude)) && !isNaN(parseFloat(a.longitude))
  );

  if (loading) {
    return (
      <div style={{ display: 'flex' }}>
        <Sidebar />
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 16, color: '#64748b' }}>
          <div className="spinner" />
          <p>Chargement de la détection IA…</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex' }}>
      <Sidebar />
      <div className="page-content">
        <div className="page-shell">

          {/* ── HEADER ── */}
          <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 24, flexWrap: 'wrap', gap: 12 }}>
            <div>
              <h1 style={{ display: 'flex', alignItems: 'center', gap: 10, fontSize: '1.25rem', fontWeight: 700, margin: '0 0 4px' }}>
                <BrainCircuit size={22} color="#2563eb" />
                Validation du modèle IA
              </h1>
              <p style={{ margin: 0, fontSize: '0.82rem', color: '#64748b' }}>
                Isolation Forest · Modèle en temps réel
              </p>
            </div>
            <button
              onClick={forceIA}
              disabled={analyzing}
              style={{
                display: 'flex', alignItems: 'center', gap: 8,
                padding: '9px 18px', borderRadius: 8,
                background: '#2563eb', color: '#fff', border: 'none',
                fontWeight: 600, fontSize: '0.85rem', cursor: analyzing ? 'default' : 'pointer',
                opacity: analyzing ? 0.7 : 1
              }}
            >
              <RefreshCw size={15} style={{ animation: analyzing ? 'spin 1s linear infinite' : 'none' }} />
              {analyzing ? 'Analyse en cours…' : 'Forcer l\'analyse IA'}
            </button>
          </div>

          {/* ── KPIs ── */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: 14, marginBottom: 24 }}>
            {[
              { label: 'Antennes analysées', value: nb.total, color: '#2563eb', bg: 'rgba(37,99,235,0.08)', icon: <CheckCircle2 size={20} color="#2563eb" /> },
              { label: 'Anomalies détectées', value: nb.alerte + nb.critique, color: '#d97706', bg: 'rgba(217,119,6,0.08)', icon: <AlertTriangle size={20} color="#d97706" /> },
              { label: 'Score IA moyen', value: `${avgRisk}%`, color: '#059669', bg: 'rgba(5,150,105,0.08)', icon: <Activity size={20} color="#059669" /> },
              { label: 'Dernière analyse IA', value: lastUpdate ? lastUpdate.toLocaleTimeString('fr-FR') : '--:--', color: '#64748b', bg: 'rgba(100,116,139,0.08)', icon: <RefreshCw size={20} color="#64748b" /> },
              { label: 'Taux confiance IA', value: '98.5%', color: '#7c3aed', bg: 'rgba(124,58,237,0.08)', icon: <BrainCircuit size={20} color="#7c3aed" /> },
            ].map(k => (
              <div key={k.label} style={{
                background: '#fff', border: '1px solid #e2e8f0', borderRadius: 12,
                borderTop: `3px solid ${k.color}`,
                padding: '16px 14px', display: 'flex', alignItems: 'center', gap: 14,
                boxShadow: '0 1px 3px rgba(0,0,0,0.06)'
              }}>
                <div style={{ width: 40, height: 40, borderRadius: 10, background: k.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                  {k.icon}
                </div>
                <div>
                  <div style={{ fontSize: '0.72rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: '#64748b', marginBottom: 2 }}>
                    {k.label}
                  </div>
                  <div style={{ fontSize: '1.3rem', fontWeight: 800, color: k.color, lineHeight: 1 }}>
                    {k.value}
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* ── CARTE LEAFLET ── */}
          <div style={{
            background: '#fff', border: '1px solid #e2e8f0', borderRadius: 12,
            marginBottom: 24, overflow: 'hidden', boxShadow: '0 1px 3px rgba(0,0,0,0.06)'
          }}>
            <div style={{ padding: '14px 20px', borderBottom: '1px solid #e2e8f0', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
              <h3 style={{ margin: 0, fontSize: '0.9rem', fontWeight: 700, display: 'flex', alignItems: 'center', gap: 8 }}>
                <RadioTower size={16} color="#2563eb" /> Carte réseau temps réel
              </h3>
              <div style={{ display: 'flex', gap: 14, fontSize: '0.75rem', color: '#64748b' }}>
                <span>🟢 Normal ({nb.normal})</span>
                <span>🟠 Alerte ({nb.alerte})</span>
                <span>🔴 Critique ({nb.critique})</span>
              </div>
            </div>
            <div style={{ height: 380 }}>
              <MapContainer
                center={[35.40, 10.80]}
                zoom={10}
                style={{ height: '100%', width: '100%' }}
                scrollWheelZoom={true}
              >
                <TileLayer
                  url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
                  attribution='&copy; CartoDB'
                />
                <FitBounds antennes={marqueurs} />
                {marqueurs.map(ant => {
                  const lat = parseFloat(ant.latitude);
                  const lon = parseFloat(ant.longitude);
                  const color = couleurStatut(ant.statut);
                  const r = ant.statut === 'critique' ? 10 : ant.statut === 'alerte' ? 8 : 6;
                  return (
                    <CircleMarker
                      key={`${ant.id}-${ant.statut}`}
                      center={[lat, lon]}
                      radius={r}
                      fillColor={color}
                      color={color}
                      weight={2}
                      fillOpacity={0.75}
                      opacity={1}
                    >
                      <Popup>
                        <div style={{ minWidth: 160, fontFamily: 'Inter, sans-serif' }}>
                          <div style={{ fontWeight: 700, fontSize: '0.9rem', marginBottom: 6 }}>{ant.nom}</div>
                          <div style={{ fontSize: '0.78rem', color: '#64748b', marginBottom: 8 }}>Zone : {ant.zone}</div>
                          <table style={{ width: '100%', fontSize: '0.78rem', borderCollapse: 'collapse' }}>
                            <tbody>
                              {[
                                ['CPU', `${Number(ant.cpu || 0).toFixed(1)} %`],
                                ['Température', `${Number(ant.temperature || 0).toFixed(1)} °C`],
                                ['Latence', `${Number(ant.latence || 0).toFixed(0)} ms`],
                                ['Disponibilité', `${Number(ant.disponibilite || 0).toFixed(1)} %`],
                                ['Score IA', `${Number(ant.risk_score || 0).toFixed(1)} %`],
                              ].map(([k, v]) => (
                                <tr key={k}>
                                  <td style={{ color: '#64748b', paddingRight: 10, paddingBottom: 3 }}>{k}</td>
                                  <td style={{ fontWeight: 600 }}>{v}</td>
                                </tr>
                              ))}
                            </tbody>
                          </table>
                          <div style={{
                            marginTop: 8, padding: '4px 8px', borderRadius: 4,
                            background: ant.statut === 'critique' ? '#fef2f2' : ant.statut === 'alerte' ? '#fffbeb' : '#f0fdf4',
                            color,
                            fontWeight: 700, fontSize: '0.75rem', textAlign: 'center'
                          }}>
                            {ant.statut === 'critique' ? '🔴 CRITIQUE' : ant.statut === 'alerte' ? '🟠 ALERTE' : '🟢 NORMAL'}
                          </div>
                        </div>
                      </Popup>
                    </CircleMarker>
                  );
                })}
              </MapContainer>
            </div>
          </div>

          {/* ── TABLEAU ANOMALIES ── */}
          <div style={{
            background: '#fff', border: '1px solid #e2e8f0', borderRadius: 12,
            boxShadow: '0 1px 3px rgba(0,0,0,0.06)', overflow: 'hidden'
          }}>
            <div style={{ padding: '14px 20px', borderBottom: '1px solid #e2e8f0', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 10 }}>
              <h3 style={{ margin: 0, fontSize: '0.9rem', fontWeight: 700, display: 'flex', alignItems: 'center', gap: 8 }}>
                <Activity size={16} color="#2563eb" /> Résultats Validation IA
              </h3>
            </div>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.82rem' }}>
                <thead>
                  <tr style={{ background: '#f8fafc' }}>
                    {['Antenne', 'Score IA', 'Statut', 'Décision IA'].map(h => (
                      <th key={h} style={{ padding: '10px 14px', textAlign: 'left', fontWeight: 700, fontSize: '0.7rem', textTransform: 'uppercase', letterSpacing: '0.06em', color: '#64748b', borderBottom: '1px solid #e2e8f0', whiteSpace: 'nowrap' }}>
                        {h}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {tableau.slice(0, 50).map((ant, idx) => {
                    const color = couleurStatut(ant.statut);
                    const bgRow = ant.statut === 'critique' ? 'rgba(220,38,38,0.03)' : ant.statut === 'alerte' ? 'rgba(217,119,6,0.03)' : 'transparent';
                    return (
                      <tr key={ant.id} style={{ background: idx % 2 === 0 ? bgRow : '#fff', borderBottom: '1px solid rgba(226,232,240,0.5)' }}>
                        <td style={{ padding: '10px 14px', fontWeight: 600, color: '#0f172a' }}>{ant.nom}</td>
                        <td style={{ padding: '10px 14px', fontWeight: 700, color: '#2563eb' }}>
                          {Number(ant.risk_score || 0).toFixed(1)}%
                        </td>
                        <td style={{ padding: '10px 14px' }}>
                          <span style={{
                            display: 'inline-block', padding: '3px 10px', borderRadius: 20,
                            fontSize: '0.72rem', fontWeight: 700,
                            background: ant.statut === 'critique' ? 'rgba(220,38,38,0.1)' : ant.statut === 'alerte' ? 'rgba(217,119,6,0.1)' : 'rgba(5,150,105,0.1)',
                            color
                          }}>
                            {ant.statut === 'critique' ? 'Critique' : ant.statut === 'alerte' ? 'Alerte' : 'Normal'}
                          </span>
                        </td>
                        <td style={{ padding: '10px 14px', fontWeight: 700, color: color }}>
                          {ant.statut}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
              {tableau.length === 0 && (
                <div style={{ padding: 40, textAlign: 'center', color: '#94a3b8' }}>
                  <BrainCircuit size={28} style={{ marginBottom: 8 }} />
                  <p>Aucune antenne trouvée.</p>
                </div>
              )}
              {tableau.length > 50 && (
                <div style={{ padding: '10px 20px', fontSize: '0.78rem', color: '#94a3b8', textAlign: 'center', borderTop: '1px solid #e2e8f0' }}>
                  Affichage des 50 premières antennes sur {tableau.length} — utilisez la recherche pour filtrer.
                </div>
              )}
            </div>
          </div>

        </div>
      </div>

      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        .spinner {
          width: 32px; height: 32px;
          border: 3px solid #e2e8f0;
          border-top-color: #2563eb;
          border-radius: 50%;
          animation: spin 0.8s linear infinite;
        }
      `}</style>
    </div>
  );
}
